const GuardrailConfiguration = @import("guardrail_configuration.zig").GuardrailConfiguration;
const PromptFlowNodeSourceConfiguration = @import("prompt_flow_node_source_configuration.zig").PromptFlowNodeSourceConfiguration;

/// Contains configurations for a prompt node in the flow. You can use a prompt
/// from Prompt management or you can define one in this node. If the prompt
/// contains variables, the inputs into this node will fill in the variables.
/// The output from this node is the response generated by the model. For more
/// information, see [Node types in a
/// flow](https://docs.aws.amazon.com/bedrock/latest/userguide/flows-nodes.html)
/// in the Amazon Bedrock User Guide.
pub const PromptFlowNodeConfiguration = struct {
    /// Contains configurations for a guardrail to apply to the prompt in this node
    /// and the response generated from it.
    guardrail_configuration: ?GuardrailConfiguration = null,

    /// Specifies whether the prompt is from Prompt management or defined inline.
    source_configuration: PromptFlowNodeSourceConfiguration,

    pub const json_field_names = .{
        .guardrail_configuration = "guardrailConfiguration",
        .source_configuration = "sourceConfiguration",
    };
};
